const EARTH_RADIUS = 6371000; // meters

export function haversineDistance(
  lat1: number, lng1: number,
  lat2: number, lng2: number,
): number {
  const toRad = (d: number) => (d * Math.PI) / 180;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng / 2) ** 2;
  return EARTH_RADIUS * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

export function polylineTotalLength(latlngs: [number, number][]): number {
  let total = 0;
  for (let i = 1; i < latlngs.length; i++) {
    total += haversineDistance(
      latlngs[i - 1][0], latlngs[i - 1][1],
      latlngs[i][0], latlngs[i][1],
    );
  }
  return total;
}

export function polylineSegmentLengths(latlngs: [number, number][]): number[] {
  const segs: number[] = [];
  for (let i = 1; i < latlngs.length; i++) {
    segs.push(haversineDistance(
      latlngs[i - 1][0], latlngs[i - 1][1],
      latlngs[i][0], latlngs[i][1],
    ));
  }
  return segs;
}

export function getPolylineMidpoint(latlngs: [number, number][]): [number, number] {
  if (latlngs.length === 0) return [0, 0];
  const mid = Math.floor(latlngs.length / 2);
  return latlngs[Math.min(mid, latlngs.length - 1)];
}

export function formatDistance(meters: number): string {
  if (meters >= 1000) return `${(meters / 1000).toFixed(3)} كم`;
  return `${meters.toFixed(1)} م`;
}

export function formatNum(n: number, decimals = 2): string {
  return n.toLocaleString('ar-EG', {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  });
}

export interface EngQuantities {
  roadArea: number;
  cutVolume: number;
  fillVolume: number;
  leanConcrete: number;
  mainConcrete: number;
  steelWeight: number;
  paintArea: number;
}

export function calcQuantities(
  totalLength: number,
  roadWidth: number,
  cutDepth: number,
  fillHeight: number,
  leanThickness: number,
  mainThickness: number,
): EngQuantities {
  const roadArea = totalLength * roadWidth;
  return {
    roadArea,
    cutVolume: roadArea * cutDepth,
    fillVolume: roadArea * fillHeight,
    leanConcrete: roadArea * leanThickness,
    mainConcrete: roadArea * mainThickness,
    steelWeight: roadArea * mainThickness * 80,
    paintArea: totalLength * 0.15,
  };
}

export interface RoadData {
  id: string;
  name: string;
  latlngs: [number, number][];
  totalLength: number;
  segmentLengths: number[];
}

export interface PointData {
  id: string;
  name: string;
  latlng: [number, number];
}
